// ---- CONFIG ----
const PIPELINE_SECRET   = 'YOUR_PIPELINE_SECRET';
const LAUNCHER_SECRET   = 'YOUR_LAUNCHER_SECRET';
const LAUNCHER_URL      = 'http://10.1.4.232:8765/launch';
const TELEGRAM_BOT_URL  = 'https://api.telegram.org/botYOUR_TELEGRAM_BOT_TOKEN/sendMessage';
const TELEGRAM_CHAT_ID  = 935389847;

// ---- STAGE DEFINITIONS ----
const STAGES = {
  M2: {
    pass_criteria: { ep7_success_rate: 0.80 },
    pass: { stage: 'M3b', config: 'training/configs/m3b_all_eps_tqc.yaml', module: 'training.train_m3_all_eps' },
    fail: { stage: 'HUMAN_REVIEW', note: 'M2 failed — manual intervention required' }
  },
  M3: {
    pass_criteria: { overall_success_rate: 0.75 },
    pass: { stage: 'M3b', config: 'training/configs/m3b_all_eps_tqc.yaml', module: 'training.train_m3_all_eps' },
    fail: { stage: 'M3b', config: 'training/configs/m3b_all_eps_tqc.yaml', module: 'training.train_m3_all_eps' }
  },
  M3b: {
    pass_criteria: { overall_success_rate: 0.75 },
    pass: { stage: 'M4', config: 'training/configs/m4_transitions_tqc.yaml', module: 'training.train_m4_transitions', note: 'Set pretrained_policy in config before launch' },
    fail: { stage: 'M3c', config: 'training/configs/m3c_all_eps_tqc.yaml', module: 'training.train_m3_all_eps' }
  },
  M3c: {
    pass_criteria: { overall_success_rate: 0.75 },
    pass: { stage: 'M4', config: 'training/configs/m4_transitions_tqc.yaml', module: 'training.train_m4_transitions', note: 'Set pretrained_policy in config before launch' },
    fail: { stage: 'HUMAN_REVIEW', note: 'M3c failed — hyperparameter tuning needed' }
  },
  M4: {
    pass_criteria: { overall_success_rate: 0.80 },
    pass: { stage: 'HUMAN_REVIEW', note: 'M4 passed (≥ 80% over 56 transitions) — proceed to M5 domain randomization' },
    fail: { stage: 'HUMAN_REVIEW', note: 'M4 failed — extend budget or tune curriculum' }
  }
};

// ---- VALIDATE SECRET ----
const _raw = $input.first().json;
const body = _raw.body || _raw;
const incomingSecret = body.pipeline_secret || '';
if (incomingSecret !== PIPELINE_SECRET) {
  throw new Error('Invalid pipeline secret');
}

// ---- PARSE ----
const milestone = body.milestone || 'UNKNOWN';
const metrics   = body.metrics   || {};
const runName   = body.run_name  || 'unknown';
const runId     = body.run_id    || 'unknown';

// ---- EVALUATE ----
const stageDef = STAGES[milestone];
let passed = false;
let next   = { stage: 'HUMAN_REVIEW', note: 'Stage not defined' };
let reasons = [];

if (stageDef) {
  const criteria = stageDef.pass_criteria;
  const checks = Object.entries(criteria).map(([k, threshold]) => {
    const actual = typeof metrics[k] === 'number' ? metrics[k] : 0;
    const ok = actual >= threshold;
    reasons.push(`${k}: ${(actual*100).toFixed(0)}% (need ${(threshold*100).toFixed(0)}%) ${ok ? '\u2705' : '\u274c'}`);
    return ok;
  });
  passed = checks.every(Boolean);
  next   = passed ? stageDef.pass : stageDef.fail;
}

// ---- LAUNCH PAYLOAD ----
const canLaunch = next.stage && next.stage !== 'HUMAN_REVIEW' && next.module && next.config;
const launchPayload = canLaunch ? { secret: LAUNCHER_SECRET, module: next.module, config: next.config } : null;

// ---- TELEGRAM MESSAGE ----
const bars = [0,1,2,3,4,5,6,7].map(i => {
  const sr = metrics['ep' + i + '_success_rate'];
  const b = typeof sr === 'number' ? (sr >= 0.8 ? '\uD83D\uDFE2' : sr >= 0.5 ? '\uD83D\uDFE1' : '\uD83D\uDD34') : '\u25A1';
  return 'EP' + i + ': ' + b + ' ' + (typeof sr === 'number' ? (sr*100).toFixed(0) + '%' : 'n/a');
}).join('  ');

const icon = passed ? '\u2705' : '\u26A0\uFE0F';
const lines = [
  '*Triple Pendulum — ' + milestone + ' ' + icon + '*',
  'Run: `' + runName + '`',
  '',
  '*Criteria:*',
  reasons.join('\n'),
  '',
  '*Per-EP success:*',
  bars,
  '',
  canLaunch
    ? '*Next: launching ' + next.stage + '*\n`' + next.config + '`'
    : '*Next: ' + next.stage + '*\n' + (next.note || '')
];
const message = lines.join('\n');

return [{ json: {
  milestone, runName, runId, passed, next, launchPayload, hasNextStage: canLaunch, message,
  telegramBotUrl: TELEGRAM_BOT_URL,
  telegramChatId: TELEGRAM_CHAT_ID,
  launcherUrl: LAUNCHER_URL,
  metrics
} }];
